import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import styles from '../pages/PageStyle2.module.css';

function EditBookPage() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    seriesTitle: '',
    seriesStartDate: '',
    seriesEndDate: '',
    publisher: '',
    issueNumber: '',
    releaseDate: '',
    coverArt: '',
  });
  const [tags, setTags] = useState([]);
  const [currentTag, setCurrentTag] = useState('');
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const formatDateForInput = (dateString) => {
    if (!dateString) return '';
    return new Date(dateString).toISOString().split('T')[0];
  };

  useEffect(() => {
    const fetchBook = async () => {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        const { data } = await axios.get(`/api/books/${id}`, config);
        setFormData({
          seriesTitle: data.seriesTitle,
          seriesStartDate: formatDateForInput(data.seriesStartDate),
          seriesEndDate: formatDateForInput(data.seriesEndDate),
          publisher: data.publisher,
          issueNumber: data.issueNumber,
          releaseDate: formatDateForInput(data.releaseDate),
          coverArt: data.coverArt || '',
        });
        setTags(data.tags || []);
      } catch (err) {
        setError('Could not fetch book data.');
      }
    };
    fetchBook();
  }, [id]);

  const onChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleAddTag = () => {
    if (currentTag && !tags.includes(currentTag)) {
      setTags([...tags, currentTag]);
      setCurrentTag('');
    }
  };

  const handleRemoveTag = (tagToRemove) => {
    setTags(tags.filter(tag => tag !== tagToRemove));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');

    try {
      const userInfo = JSON.parse(localStorage.getItem('userInfo'));
      const config = {
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${userInfo.token}`,
        },
      };

      const bookData = { ...formData, tags, seriesEndDate: formData.seriesEndDate || null };
      await axios.put(`/api/books/${id}`, bookData, config);
      setMessage('Book updated successfully!');
    } catch (err) {
      setError(err.response?.data?.message || 'An error occurred during update.');
    }
  };

  const handleDelete = async () => {
    if (window.confirm('Are you sure you want to permanently delete this book? This action cannot be undone.')) {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        await axios.delete(`/api/books/${id}`, config);
        navigate('/inventory');
      } catch (err) {
        setError(err.response?.data?.message || 'Could not delete book.');
      }
    }
  };

  return (
    <EmployeeLayout title="Edit Book">
      {message && <p className={styles.message}>{message}</p>}
      {error && <p className={styles.error}>{error}</p>}
      <div>
        <form onSubmit={handleSubmit}>
          <div><label>Series Title*:</label><input type="text" name="seriesTitle" value={formData.seriesTitle} onChange={onChange} required /></div>
          <div><label>Series Start Date*:</label><input type="date" name="seriesStartDate" value={formData.seriesStartDate} onChange={onChange} required /></div>
          <div><label>Series End Date:</label><input type="date" name="seriesEndDate" value={formData.seriesEndDate} onChange={onChange} /></div>
          <div><label>Publisher*:</label><input type="text" name="publisher" value={formData.publisher} onChange={onChange} required /></div>
          <div><label>Issue Number*:</label><input type="number" name="issueNumber" value={formData.issueNumber} onChange={onChange} required /></div>
          <div><label>Release Date*:</label><input type="date" name="releaseDate" value={formData.releaseDate} onChange={onChange} required /></div>
          <div><label>Cover Art Path:</label><input type="text" name="coverArt" value={formData.coverArt} onChange={onChange} /></div>
          <div>
            <label>Tags:</label>
            <input
              type="text"
              value={currentTag}
              onChange={(e) => setCurrentTag(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); handleAddTag(); } }}
            />
            <button type="button" onClick={handleAddTag}>Add Tag</button>
            <div>
              {tags.map(tag => (
                <span key={tag} style={{ border: '1px solid #ccc', borderRadius: '3px', padding: '2px 5px', marginRight: '5px' }}>
                  {tag}
                  <button type="button" onClick={() => handleRemoveTag(tag)} style={{ marginLeft: '5px', border: 'none', background: 'transparent', color: 'red', cursor: 'pointer' }}>x</button>
                </span>
              ))}
            </div>
          </div>
          <button type="submit">Save</button>
          <button type="button" onClick={() => navigate('/inventory')}>Cancel</button>
          <button type="button" onClick={handleDelete} style={{ backgroundColor: 'red', color: 'white' }}>Delete</button>
        </form>
      </div>
    </EmployeeLayout>
  );
}

export default EditBookPage;
